    23→
    24→const generateTimeSlots = (
    25→  startHour: number,
    26→  endHour: number,
    27→  slotMinutes: number
    28→): TimeSlot[] => {
    29→  const slots: TimeSlot[] = [];
    30→  let currentHour = startHour;
    31→  let currentMinute = 0;
    32→
    33→  while (
    34→    currentHour < endHour ||
    35→    (currentHour === endHour && currentMinute === 0)
    36→  ) {
    37→    const label = `${currentHour.toString().padStart(2, "0")}:${currentMinute
    38→      .toString()
    39→      .padStart(2, "0")}`;
    40→    const time = `${currentHour}:${currentMinute.toString().padStart(2, "0")}`;
    41→
    42→    slots.push({
    43→      hour: currentHour,
    44→      minute: currentMinute,
    45→      label,
    46→      time,
    47→    });
    48→
    49→    currentMinute += slotMinutes;
    50→    if (currentMinute >= 60) {
    51→      currentMinute = 0;
    52→      currentHour += 1;
    53→    }
    54→  }
    55→
    56→  return slots;
    57→};
    58→
    59→const calculateCurrentTimePosition = (
    60→  currentDate: Date,
    61→  timeSlots: TimeSlot[],
    62→  slotHeight: number,
    63→  timezone?: string
    64→): number | undefined => {
    65→  if (timeSlots.length === 0) return undefined;
    66→
    67→  // Get current time in the salon's timezone
    68→  // We need to extract hours and minutes in the salon's timezone, not local browser timezone
    69→  const currentHour = timezone
    70→    ? parseInt(formatInTimeZone(currentDate, timezone, "HH"), 10)
    71→    : currentDate.getHours();
    72→  const currentMinute = timezone
    73→    ? parseInt(formatInTimeZone(currentDate, timezone, "mm"), 10)
    74→    : currentDate.getMinutes();
    75→
    76→  const firstSlot = timeSlots[0];
    77→  const currentTotalMinutes = currentHour * 60 + currentMinute;
    78→  const firstSlotMinutes = firstSlot.hour * 60 + firstSlot.minute;
    79→
    80→  // If current time is before the first slot, return 0
    81→  if (currentTotalMinutes < firstSlotMinutes) return 0;
    82→
    83→  const minutesFromFirst = currentTotalMinutes - firstSlotMinutes;
    84→
    85→  const slotMinutes =
    86→    timeSlots.length > 1
    87→      ? timeSlots[1].hour * 60 + timeSlots[1].minute - firstSlotMinutes
    88→      : 15;
    89→
    90→  const position = (minutesFromFirst / slotMinutes) * slotHeight;
    91→
    92→  return position;
    93→};
