   187→      }
   188→    };
   189→    measure();
   190→    window.addEventListener("resize", measure);
   191→    return () => window.removeEventListener("resize", measure);
   192→  }, [columns]);
   193→
   194→  // Focus and Scroll Effect (Desktop)
