   260→          </h3>
   261→          <p className="text-body text-muted-foreground max-w-md">
   262→            Para utilizar a agenda, é necessário cadastrar pelo menos um
   263→            profissional no salão.
   264→          </p>
   265→          <p className="text-body text-muted-foreground mt-2">
   266→            Acesse <span className="font-semibold">Gestão de Acesso</span> para
   267→            cadastrar profissionais.
   268→          </p>
   269→        </div>
   270→      </div>
   271→    );
   272→  }
   273→
   274→  return (
   275→    <div className={outerClass}>
   276→      <div className="flex flex-col overflow-hidden h-full">
   277→
   278→        {/* ── Fixed professional header row ── */}
   279→        <div className="flex-shrink-0 border-b border-border flex">
   280→          {/* Spacer aligning with TimeGrid (w-20) */}
   281→          <div className="w-20 bg-secondary border-r border-border flex-shrink-0" />
   282→
   283→          {/* Professional names — scrolls horizontally in sync with body */}
   284→          <div ref={headerScrollRef} className="flex-1 overflow-hidden">
   285→            <div className="flex">
   286→              {columns.map((column: ProfessionalColumnType, index: number) => (
   287→                <div
   288→                  key={column.id}
   289→                  className={cn(
   290→                    "flex-1 px-2 py-2 md:px-4 md:py-3 text-center flex flex-col justify-center border-r border-border last:border-r-0",
   291→                    "min-w-[160px] md:min-w-[300px]",
   292→                    index % 2 === 0 ? "bg-secondary" : "bg-card"
   293→                  )}
   294→                >
   295→                  <div className="flex items-center justify-center gap-1.5">
   296→                    <span className="text-primary font-semibold text-body">
   297→                      {getInitials(getUserDisplayName(column))}
   298→                    </span>
   299→                  </div>
   300→                  <div className="text-button text-muted-foreground mt-1 font-normal break-words leading-tight">
   301→                    {getUserDisplayName(column)}
   302→                  </div>
   303→                </div>
   304→              ))}
   305→            </div>
   306→          </div>
   307→
   308→          {/* Compensate vertical scrollbar width so header aligns with body */}
   309→          {scrollbarWidth > 0 && (
   310→            <div
   311→              className="bg-muted flex-shrink-0"
   312→              style={{ width: scrollbarWidth }}
   313→            />
   314→          )}
   315→        </div>
   316→
   317→        {/* ── Scrollable calendar body ── */}
   318→        <div
   319→          ref={scrollContainerRef}
   320→          className="flex-1 overflow-auto"
   321→          onScroll={handleBodyScroll}
   322→        >
   323→          <div className="flex min-h-full">
   324→            <TimeGrid
   325→              timeSlots={timeSlots}
   326→              slotHeight={slotHeight}
   327→              currentTimePosition={currentTimePosition}
   328→            />
   329→
   330→            <div className="flex flex-1 overflow-hidden">
   331→              {columns.map((column: ProfessionalColumnType, index: number) => {
   332→                const columnEvents = events.filter(
   333→                  (event) => event.professionalId === column.id
   334→                );
   335→                return (
   336→                  <ProfessionalColumn
   337→                    key={column.id}
   338→                    professional={column}
   339→                    columnIndex={index}
   340→                    events={columnEvents}
   341→                    timeSlots={timeSlots}
   342→                    slotHeight={slotHeight}
   343→                    primaryColor={primaryColor}
   344→                    onEventClick={onEventClick}
   345→                    onSlotClick={onSlotClick}
   346→                    onAbsenceClick={onAbsenceClick}
   347→                    onAbsenceBlockClick={onAbsenceBlockClick}
   348→                    isPastDay={isPastDay}
   349→                    selectedDate={calendarDate}
   350→                    highlightAppointmentId={focusAppointment?.id ?? null}
   351→                  />
   352→                );
   353→              })}
   354→            </div>
   355→          </div>
   356→        </div>
   357→
   358→      </div>
   359→    </div>
   360→  );
   361→};
