   104→const calculateEventPosition = (
   105→  event: CalendarEvent,
   106→  timeSlots: TimeSlot[],
   107→  slotHeight: number,
   108→  salonTimezone: string
   109→): EventPosition => {
   110→  // Converter UTC para timezone do salão
   111→  const startTime = extractTimeComponents(event.start, salonTimezone);
   112→  const endTime = extractTimeComponents(event.end, salonTimezone);
   113→
   114→  const startHour = startTime.hours;
   115→  const startMinute = startTime.minutes;
   116→  const endHour = endTime.hours;
   117→  const endMinute = endTime.minutes;
   118→
   119→  const firstSlot = timeSlots[0];
   120→  const lastSlot = timeSlots[timeSlots.length - 1];
   121→
   122→  const firstSlotMinutes = firstSlot.hour * 60 + firstSlot.minute;
   123→  const lastSlotMinutes = lastSlot.hour * 60 + lastSlot.minute;
   124→
   125→  const eventStartMinutes = startHour * 60 + startMinute;
   126→  const eventEndMinutes = endHour * 60 + endMinute;
   127→
   128→  // Calculate slot duration dynamically
   129→  const slotMinutes =
   130→    timeSlots.length > 1
   131→      ? timeSlots[1].hour * 60 + timeSlots[1].minute - firstSlotMinutes
   132→      : 15;
   133→
   134→  // Clamp event start to visible area
   135→  const clampedStartMinutes = Math.max(eventStartMinutes, firstSlotMinutes);
   136→  const clampedEndMinutes = Math.min(eventEndMinutes, lastSlotMinutes + slotMinutes);
   137→
   138→  const startMinutesFromFirst = clampedStartMinutes - firstSlotMinutes;
   139→  const durationMinutes = clampedEndMinutes - clampedStartMinutes;
   140→
   141→  const top = (startMinutesFromFirst / slotMinutes) * slotHeight;
   142→  const height = Math.max((durationMinutes / slotMinutes) * slotHeight, 25); // Minimum 25px height (half slot)
   143→
   144→  return { top, height };
   145→};
