   147→/**
   148→ * Verifica se dois eventos se sobrepõem temporalmente
   149→ */
   150→const eventsOverlap = (event1: CalendarEvent, event2: CalendarEvent): boolean => {
   151→  const start1 = new Date(event1.start).getTime();
   152→  const end1 = new Date(event1.end).getTime();
   153→  const start2 = new Date(event2.start).getTime();
   154→  const end2 = new Date(event2.end).getTime();
   155→
   156→  return start1 < end2 && start2 < end1;
   157→};
   158→
   159→/**
   160→ * Detecta grupos de eventos que se sobrepõem
   161→ * Retorna array de grupos, onde cada grupo contém eventos sobrepostos
   162→ */
   163→const detectCollisionGroups = (events: CalendarEvent[]): CalendarEvent[][] => {
   164→  if (events.length === 0) return [];
   165→
   166→  // Ordena eventos por horário de início, depois por ID (ordem de criação)
   167→  const sortedEvents = [...events].sort((a, b) => {
   168→    const timeCompare = new Date(a.start).getTime() - new Date(b.start).getTime();
   169→    if (timeCompare !== 0) return timeCompare;
   170→    return a.id.localeCompare(b.id);
   171→  });
   172→
   173→  const groups: CalendarEvent[][] = [];
   174→  const processed = new Set<string>();
   175→
   176→  sortedEvents.forEach((event) => {
   177→    if (processed.has(event.id)) return;
   178→
   179→    // Inicia novo grupo com este evento
   180→    const group = [event];
   181→    processed.add(event.id);
   182→
   183→    // Encontra todos os eventos que se sobrepõem com algum evento do grupo
   184→    let foundOverlap = true;
   185→    while (foundOverlap) {
   186→      foundOverlap = false;
   187→      sortedEvents.forEach((candidate) => {
   188→        if (processed.has(candidate.id)) return;
   189→
   190→        // Verifica se candidate se sobrepõe com algum evento do grupo
   191→        const overlaps = group.some((groupEvent) =>
   192→          eventsOverlap(groupEvent, candidate)
   193→        );
   194→
   195→        if (overlaps) {
   196→          group.push(candidate);
   197→          processed.add(candidate.id);
   198→          foundOverlap = true;
   199→        }
   200→      });
   201→    }
   202→
   203→    groups.push(group);
   204→  });
   205→
   206→  return groups;
   207→};
   208→
   209→/**
   210→ * Calcula o layout (sub-coluna) para cada evento considerando colisões
   211→ */
   212→const calculateEventLayouts = (
   213→  events: CalendarEvent[],
   214→  timeSlots: TimeSlot[],
   215→  slotHeight: number,
   216→  salonTimezone: string
   217→): EventLayout[] => {
   218→  if (events.length === 0) return [];
   219→
   220→  const collisionGroups = detectCollisionGroups(events);
   221→  const layouts: EventLayout[] = [];
   222→
   223→  collisionGroups.forEach((group) => {
   224→    if (group.length === 1) {
   225→      // Sem colisão - ocupa largura total
   226→      const event = group[0];
   227→      layouts.push({
   228→        event,
   229→        position: calculateEventPosition(event, timeSlots, slotHeight, salonTimezone),
   230→        column: 0,
   231→        totalColumns: 1,
   232→      });
   233→    } else {
   234→      // Múltiplos eventos sobrepostos - calcula sub-colunas
   235→      // Ordena grupo por início e ID
   236→      const sortedGroup = [...group].sort((a, b) => {
   237→        const timeCompare = new Date(a.start).getTime() - new Date(b.start).getTime();
   238→        if (timeCompare !== 0) return timeCompare;
   239→        return a.id.localeCompare(b.id);
   240→      });
   241→
   242→      // Atribui cada evento a uma coluna
   243→      const columnAssignments = new Map<string, number>();
   244→      const maxColumnsNeeded = sortedGroup.length;
   245→
   246→      sortedGroup.forEach((event, index) => {
   247→        // Encontra a primeira coluna disponível
   248→        let column = 0;
   249→        const occupiedColumns = new Set<number>();
   250→
   251→        // Verifica quais colunas estão ocupadas por eventos que se sobrepõem
   252→        sortedGroup.forEach((other, otherIndex) => {
   253→          if (otherIndex >= index) return; // Só verifica eventos já processados
   254→
   255→          if (eventsOverlap(event, other)) {
   256→            const otherColumn = columnAssignments.get(other.id);
   257→            if (otherColumn !== undefined) {
   258→              occupiedColumns.add(otherColumn);
   259→            }
   260→          }
   261→        });
   262→
   263→        // Encontra primeira coluna livre
   264→        while (occupiedColumns.has(column)) {
   265→          column++;
   266→        }
   267→
   268→        columnAssignments.set(event.id, column);
   269→      });
   270→
   271→      // Calcula o número máximo de colunas necessárias
   272→      const maxColumn = Math.max(...Array.from(columnAssignments.values()));
   273→      const totalColumns = maxColumn + 1;
   274→
   275→      // Cria layouts para todos os eventos do grupo
   276→      sortedGroup.forEach((event) => {
   277→        layouts.push({
   278→          event,
   279→          position: calculateEventPosition(event, timeSlots, slotHeight, salonTimezone),
   280→          column: columnAssignments.get(event.id) || 0,
   281→          totalColumns,
   282→        });
   283→      });
   284→    }
   285→  });
   286→
   287→  return layouts;
   288→};
