   290→type BlockReason =
   291→  | "salon-closed"
   292→  | "past"
   293→  | "not-working"
   294→  | "outside-professional-hours"
   295→  | "break"
   296→  | "ausencia"
   297→  | "indisponibilidade";
   298→
   299→interface BlockStatus {
   300→  blocked: boolean;
   301→  reason?: BlockReason;
   302→}
   303→
   304→const DAY_MAP: Record<number, keyof ProfessionalSchedule> = {
   305→  0: "sunday",
   306→  1: "monday",
   307→  2: "tuesday",
   308→  3: "wednesday",
   309→  4: "thursday",
   310→  5: "friday",
   311→  6: "saturday",
   312→} as const;
   313→
   314→const parseTimeToMinutes = (time: string): number => {
   315→  const parts = time.split(":");
   316→  const hours = parseInt(parts[0], 10);
   317→  const minutes = parseInt(parts[1], 10);
   318→  return hours * 60 + minutes;
   319→};
   320→
   321→/**
   322→ * Default timezone for salons (Brazil/São Paulo)
   323→ * Used as fallback when salon timezone is not specified
   324→ */
   325→const DEFAULT_SALON_TIMEZONE = "America/Sao_Paulo";
   326→
   327→/**
   328→ * Gets current time in minutes in the salon's timezone
   329→ * @param salonTimezone - IANA timezone string (e.g., "America/Sao_Paulo", "Europe/Lisbon")
   330→ * @returns Current time in minutes since midnight in salon's timezone
   331→ */
   332→const getCurrentSalonTimeInMinutes = (salonTimezone?: string): number => {
   333→  const now = new Date();
   334→  const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   335→
   336→  // Format current time in salon's timezone as HH:mm
   337→  const timeString = formatInTimeZone(now, timezone, "HH:mm");
   338→  return parseTimeToMinutes(timeString);
   339→};
   340→
   341→const getUTCDateString = (date: Date): string => {
   342→  return date.toISOString().split("T")[0];
   343→};
   344→
   345→const getTodayUTCDateString = (): string => {
   346→  return new Date().toISOString().split("T")[0];
   347→};
   348→
   349→const isDateBeforeToday = (date: Date): boolean => {
   350→  const todayUTC = getTodayUTCDateString();
   351→  const dateUTC = getUTCDateString(date);
   352→  return dateUTC < todayUTC;
   353→};
   354→
   355→const isToday = (date: Date): boolean => {
   356→  const todayUTC = getTodayUTCDateString();
   357→  const dateUTC = getUTCDateString(date);
   358→  return dateUTC === todayUTC;
   359→};
   360→
   361→const isSlotInPast = (
   362→  slot: TimeSlot,
   363→  selectedDate: Date,
   364→  slotDurationMinutes: number,
   365→  salonTimezone?: string
   366→): boolean => {
   367→  // Rule 1: Block ALL slots if date is before today (in UTC)
   368→  if (isDateBeforeToday(selectedDate)) {
   369→    return true;
   370→  }
   371→
   372→  // Rule 2: For today (in UTC), block only slots where the next slot has started
   373→  // This gives users the full slot duration to book
   374→  // Example: If now is 11:08 and slot is 11:00-11:30, the slot should still be available
   375→  // Only block when current time >= 11:30 (next slot start)
   376→  if (isToday(selectedDate)) {
   377→    const slotStartMinutes = parseTimeToMinutes(slot.time);
   378→    const slotEndMinutes = slotStartMinutes + slotDurationMinutes;
   379→    const currentSalonMinutes = getCurrentSalonTimeInMinutes(salonTimezone);
   380→
   381→    // Block only if we're already in the next slot (current time >= slot end time)
   382→    return currentSalonMinutes >= slotEndMinutes;
   383→  }
   384→
   385→  return false;
   386→};
   387→
   388→const isSlotInBreak = (
   389→  slot: TimeSlot,
   390→  professionalSchedule: ProfessionalSchedule,
   391→  selectedDate: Date,
   392→  salonTimezone?: string
   393→): boolean => {
   394→  // Get day of week in salon timezone to ensure correct schedule lookup
   395→  const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   396→  const dayOfWeekInTimezone = parseInt(
   397→    formatInTimeZone(selectedDate, timezone, "e"),
   398→    10
   399→  );
   400→  // formatInTimeZone returns 1-7 (Mon-Sun), convert to 0-6 (Sun-Sat)
   401→  const dayOfWeek = dayOfWeekInTimezone === 7 ? 0 : dayOfWeekInTimezone;
   402→  const dayName = DAY_MAP[dayOfWeek];
   403→  const daySchedule = professionalSchedule[dayName];
   404→
   405→  if (!daySchedule?.breaks || daySchedule.breaks.length === 0) {
   406→    return false;
   407→  }
   408→
   409→  const slotMinutes = parseTimeToMinutes(slot.time);
   410→
   411→  // Rule 3: Check if slot falls within any break period
   412→  return daySchedule.breaks.some((breakPeriod) => {
   413→    const breakStartMinutes = parseTimeToMinutes(breakPeriod.start);
   414→    const breakEndMinutes = parseTimeToMinutes(breakPeriod.end);
   415→    return slotMinutes >= breakStartMinutes && slotMinutes < breakEndMinutes;
   416→  });
   417→};
   418→
   419→const isSlotBlocked = (
   420→  slot: TimeSlot,
   421→  breaks: ProfessionalColumnType["breaks"],
   422→  _isPastDay: boolean, // Deprecated - not used, kept for compatibility
   423→  professionalSchedule?: ProfessionalSchedule,
   424→  selectedDate?: Date,
   425→  salonIsOpen?: boolean,
   426→  salonTimezone?: string,
   427→  slotDurationMinutes: number = 15
   428→): BlockStatus => {
   429→  const result: BlockStatus = { blocked: false };
   430→
   431→  // Priority 1: Salon closed
   432→  if (salonIsOpen === false) {
   433→    result.blocked = true;
   434→    result.reason = "salon-closed";
   435→    return result;
   436→  }
   437→
   438→  if (!selectedDate) {
   439→    result.blocked = false;
   440→    return result;
   441→  }
   442→
   443→  // Priority 2: Past date or past time (Rules 1 & 2)
   444→  if (isSlotInPast(slot, selectedDate, slotDurationMinutes, salonTimezone)) {
   445→    result.blocked = true;
   446→    result.reason = "past";
   447→    return result;
   448→  }
   449→
   450→  // Priority 3: Check professional schedule restrictions
   451→  if (professionalSchedule) {
   452→    // Get day of week in salon timezone to ensure correct schedule lookup
   453→    const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   454→    const dayOfWeekInTimezone = parseInt(
   455→      formatInTimeZone(selectedDate, timezone, "e"),
   456→      10
   457→    );
   458→    // formatInTimeZone returns 1-7 (Mon-Sun), convert to 0-6 (Sun-Sat)
   459→    const dayOfWeek = dayOfWeekInTimezone === 7 ? 0 : dayOfWeekInTimezone;
   460→    const dayName = DAY_MAP[dayOfWeek];
   461→    const daySchedule = professionalSchedule[dayName];
   462→
   463→    if (daySchedule) {
   464→      // Professional not working this day
   465→      if (daySchedule.isWorking === false) {
   466→        result.blocked = true;
   467→        result.reason = "not-working";
   468→        return result;
   469→      }
   470→
   471→      // Check if outside professional working hours
   472→      const startTime = daySchedule.start || daySchedule.startTime;
   473→      const endTime = daySchedule.end || daySchedule.endTime;
   474→
   475→      if (startTime && endTime) {
   476→        const slotMinutes = parseTimeToMinutes(slot.time);
   477→        const professionalStartMinutes = parseTimeToMinutes(startTime);
   478→        const professionalEndMinutes = parseTimeToMinutes(endTime);
   479→
   480→        if (
   481→          slotMinutes < professionalStartMinutes ||
   482→          slotMinutes >= professionalEndMinutes
   483→        ) {
   484→          result.blocked = true;
   485→          result.reason = "outside-professional-hours";
   486→          return result;
   487→        }
   488→      }
   489→
   490→      // Priority 4: Check if slot is in break period (Rule 3)
   491→      if (
   492→        isSlotInBreak(slot, professionalSchedule, selectedDate, salonTimezone)
   493→      ) {
   494→        result.blocked = true;
   495→        result.reason = "break";
   496→        return result;
   497→      }
   498→    }
   499→  }
   500→
   501→  // Priority 5: Check for registered absences and breaks
   502→  if (breaks.length > 0 && selectedDate) {
   503→    for (const absence of breaks) {
   504→      const absenceStart = new Date(absence.start);
   505→      const absenceEnd = new Date(absence.end);
   506→
   507→      // Get UTC date parts to build date string
   508→      const year = selectedDate.getUTCFullYear();
   509→      const month = String(selectedDate.getUTCMonth() + 1).padStart(2, "0");
   510→      const day = String(selectedDate.getUTCDate()).padStart(2, "0");
   511→      const dateString = `${year}-${month}-${day}`;
   512→
   513→      // Convert slot time from salon timezone to UTC for proper comparison
   514→      // slot.time is in the salon's local time (e.g., "14:00" in America/Sao_Paulo)
   515→      // absence.start/end are in UTC
   516→      // We need to convert slot.time to UTC to compare correctly
   517→      const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   518→      const slotDateTimeUTC = convertLocalToUTC(
   519→        dateString,
   520→        slot.time,
   521→        timezone
   522→      );
   523→
   524→      // Check if slot falls within break period
   525→      const isInBreak =
   526→        slotDateTimeUTC >= absenceStart && slotDateTimeUTC < absenceEnd;
   527→
   528→      if (isInBreak) {
   529→        result.blocked = true;
   530→        result.reason = absence.type;
   531→        break;
   532→      }
   533→    }
   534→  }
   535→
   536→  return result;
   537→};
   538→
   539→export function dateInTimeZone(
   540→  timeZone: string,
   541→  year: number,
   542→  month: number,
   543→  day: number,
   544→  hour = 0,
   545→  minute = 0
   546→) {
   547→  // Monta uma data "local" no formato ISO
   548→  const localStr = `${year}-${String(month).padStart(2, "0")}-${String(
   549→    day
   550→  ).padStart(2, "0")}T${String(hour).padStart(2, "0")}:${String(
   551→    minute
   552→  ).padStart(2, "0")}:00`;
   553→
   554→  // Cria a data como se fosse em UTC
   555→  const localDate = new Date(localStr);
   556→
   557→  // Usa Intl para descobrir o deslocamento do fuso
   558→  const formatter = new Intl.DateTimeFormat("en-US", {
   559→    timeZone,
   560→    hour12: false,
   561→    year: "numeric",
   562→    month: "2-digit",
   563→    day: "2-digit",
   564→    hour: "2-digit",
   565→    minute: "2-digit",
   566→    second: "2-digit",
   567→  });
   568→
   569→  // Formata e reinterpreta como UTC
   570→  const parts = formatter.formatToParts(localDate);
   571→  const map = Object.fromEntries(parts.map((p) => [p.type, p.value]));
   572→
   573→  const zonedISO = `${map.year}-${map.month}-${map.day}T${map.hour}:${map.minute}:${map.second}`;
   574→  return new Date(zonedISO);
   575→}
   576→
   577→export function parseDateInTimeZone(timeZone: string, date: Date | string) {
   578→  const finalDate = typeof date === "string" ? new Date(date) : date;
   579→  const year = finalDate.getFullYear();
   580→  const month = finalDate.getMonth() + 1;
   581→  const day = finalDate.getDate();
   582→  const hour = finalDate.getHours();
   583→  const minute = finalDate.getMinutes();
   584→
   585→  return dateInTimeZone(timeZone, year, month, day, hour, minute);
   586→}
