   617→    [professional]
   618→  );
   619→
   620→  const salonTimezone = useMemo(
   621→    () => professional.salonTimezone,
   622→    [professional.salonTimezone]
   623→  );
   624→
   625→  // Calculate slot duration in minutes from timeSlots
   626→  const slotDurationMinutes =
   627→    timeSlots.length > 1
   628→      ? timeSlots[1].hour * 60 +
   629→      timeSlots[1].minute -
   630→      (timeSlots[0].hour * 60 + timeSlots[0].minute)
   631→      : 15;
   632→
   633→  // Check if selected date is today
   634→  const isTodayDate = useMemo(() => {
   635→    if (!selectedDate || !salonTimezone) return false;
   636→
   637→    const nowInSalonTz = toZonedTime(new Date(), salonTimezone);
   638→    const todayInSalonTz = formatInTimeZone(
