   704→
   705→  /**
   706→   * Verifica se um bloco de ausência já passou
   707→   * Um bloco é considerado "passado" se o horário de INÍCIO já passou
   708→   *
   709→   * As datas do backend vêm em UTC e são convertidas para o timezone do salão
   710→   * O startTimeStr já está convertido para o timezone do salão
   711→   *
   712→   * @param startTimeStr - Horário de início no formato "HH:mm" já convertido para timezone do salão
   713→   * @returns true se já passou (deve bloquear), false se ainda não passou (deve habilitar)
   714→   */
   715→  const isAbsenceBlockPassed = (startTimeStr: string): boolean => {
   716→    if (!selectedDate || !salonTimezone) {
   717→      return false;
   718→    }
   719→
   720→    // Extrair componentes da data em UTC (evita conversão para timezone local do browser)
   721→    const year = selectedDate.getUTCFullYear();
   722→    const month = selectedDate.getUTCMonth() + 1;
   723→    const day = selectedDate.getUTCDate();
   724→
   725→    // Criar uma data no timezone do salão usando os componentes UTC
   726→    const selectedDateInSalonTz = dateInTimeZone(
   727→      salonTimezone,
   728→      year,
   729→      month,
   730→      day,
   731→      0,
   732→      0
   733→    );
   734→
   735→    // Obter data e hora atual no timezone do salão
   736→    const nowInSalonTz = formatInTimeZone(
   737→      currentTime,
   738→      salonTimezone,
   739→      "yyyy-MM-dd HH:mm"
   740→    );
   741→    const [currentDateStr, currentTimeStr] = nowInSalonTz.split(" ");
   742→
   743→    // Obter data selecionada formatada no timezone do salão
   744→    const selectedDateStr = formatInTimeZone(
   745→      selectedDateInSalonTz,
   746→      salonTimezone,
   747→      "yyyy-MM-dd"
   748→    );
   749→
   750→    // Se a data selecionada é anterior a hoje, o bloco já passou
   751→    if (selectedDateStr < currentDateStr) {
   752→      return true;
   753→    }
   754→
   755→    // Se a data selecionada é posterior a hoje, o bloco não passou
   756→    if (selectedDateStr > currentDateStr) {
   757→      return false;
   758→    }
   759→
   760→    const [currentHour, currentMinute] = currentTimeStr.split(":").map(Number);
   761→    const currentMinutes = currentHour * 60 + currentMinute;
   762→
   763→    const startStr = formatInTimeZone(startTimeStr, salonTimezone, "HH:mm");
   764→    const [startHour, startMinute] = startStr.split(":").map(Number);
   765→    const startMinutes = startHour * 60 + startMinute;
   766→
   767→    // O bloco já passou se o horário de início é menor ou igual ao horário atual
   768→    // Ex: São 13:12 (792 min), ausência começa às 12:00 (720 min) -> bloqueado (720 <= 792 = true)
   769→    // Ex: São 13:12 (792 min), ausência começa às 13:00 (780 min) -> bloqueado (780 <= 792 = true)
   770→    // Ex: São 13:12 (792 min), ausência começa às 13:12 (792 min) -> bloqueado (792 <= 792 = true)
   771→    // Ex: São 13:12 (792 min), ausência começa às 13:15 (795 min) -> habilitado (795 <= 792 = false)
   772→    // Ex: São 13:12 (792 min), ausência começa às 15:00 (900 min) -> habilitado (900 <= 792 = false)
   773→    return startMinutes <= currentMinutes;
   774→  };
   775→
   776→  // Calculate absence block positions
   777→  const absenceBlocks = useMemo(() => {
   778→    if (!selectedDate || !salonTimezone) return [];
   779→
   780→    const firstSlot = timeSlots[0];
   781→    const firstSlotMinutes = firstSlot.hour * 60 + firstSlot.minute;
   782→
   783→    const slotMinutes =
   784→      timeSlots.length > 1
   785→        ? timeSlots[1].hour * 60 + timeSlots[1].minute - firstSlotMinutes
   786→        : 15;
   787→
   788→    // Calculate total visible height of the agenda
   789→    const totalVisibleSlots = timeSlots.length;
   790→    const maxVisibleHeight = totalVisibleSlots * slotHeight;
   791→
   792→    const blocks = professional.breaks
   793→      .filter((breakItem) => breakItem.type === "ausencia")
   794→      .map((absence) => {
   795→        // Converter UTC para timezone do salão
   796→        const startTime = extractTimeComponents(absence.start, salonTimezone);
   797→        const endTime = extractTimeComponents(absence.end, salonTimezone);
   798→
   799→        const startHour = startTime.hours;
   800→        const startMinute = startTime.minutes;
   801→        const endHour = endTime.hours;
   802→        const endMinute = endTime.minutes;
   803→
   804→        const startMinutesTotal = startHour * 60 + startMinute;
   805→        const endMinutesTotal = endHour * 60 + endMinute;
   806→
   807→        // Calculate position from first slot
   808→        const startMinutesFromFirst = startMinutesTotal - firstSlotMinutes;
   809→        const durationMinutes = endMinutesTotal - startMinutesTotal;
   810→
   811→        // Calculate top and height ensuring pixel-perfect alignment
   812→        // Round to ensure alignment with slot boundaries
   813→        let top = Math.round(
   814→          (startMinutesFromFirst / slotMinutes) * slotHeight
   815→        );
   816→        let height = Math.round((durationMinutes / slotMinutes) * slotHeight);
   817→
   818→        // Clamp to visible area
   819→        if (top < 0) {
   820→          height += top;
   821→          top = 0;
   822→        }
   823→
   824→        if (top + height > maxVisibleHeight) {
   825→          height = maxVisibleHeight - top;
   826→        }
   827→
   828→        const startTimeStr = `${startHour
   829→          .toString()
   830→          .padStart(2, "0")}:${startMinute.toString().padStart(2, "0")}`;
   831→        const endTimeStr = `${endHour.toString().padStart(2, "0")}:${endMinute
   832→          .toString()
   833→          .padStart(2, "0")}`;
   834→
   835→        const isPassed = isAbsenceBlockPassed(absence.start);
   836→
   837→        return {
   838→          id: absence.id,
   839→          top,
   840→          height: Math.max(height, 0),
   841→          startTime: startTimeStr,
   842→          endTime: endTimeStr,
   843→          reason: absence.reason,
   844→          isPassed,
   845→        };
   846→      })
   847→      // Only show blocks that are at least partially visible and have positive height
   848→      .filter((block) => block.height > 0 && block.top < maxVisibleHeight);
   849→
   850→    return blocks;
   851→  }, [
   852→    professional.breaks,
   853→    timeSlots,
   854→    slotHeight,
   855→    selectedDate,
   856→    salonTimezone,
   857→    currentTime,
   858→  ]);
