   917→
   918→          if (hasOverflow) {
   919→            // Renderiza com scroll horizontal
   920→            return (
   921→              <div className="absolute left-0 right-0 top-0 bottom-0 overflow-x-auto overflow-y-hidden">
   922→                <div className="relative" style={{ minWidth: '100%' }}>
   923→                  {eventLayouts.map((layout) => (
   924→                    <EventBlock
   925→                      key={layout.event.id}
   926→                      event={layout.event}
   927→                      position={layout.position}
   928→                      layout={{ column: layout.column, totalColumns: layout.totalColumns }}
   929→                      primaryColor={primaryColor}
   930→                      salonTimezone={salonTimezone}
   931→                      isHighlighted={layout.event.id === highlightAppointmentId}
   932→                      onClick={onEventClick}
   933→                    />
   934→                  ))}
   935→                </div>
   936→              </div>
   937→            );
   938→          }
   939→
   940→          // Renderiza normalmente sem scroll
   941→          return eventLayouts.map((layout) => (
   942→            <EventBlock
   943→              key={layout.event.id}
   944→              event={layout.event}
   945→              position={layout.position}
   946→              layout={layout}
   947→              primaryColor={primaryColor}
