   949→              onClick={onEventClick}
   950→              isHighlighted={layout.event.id === highlightAppointmentId}
   951→            />
   952→          ));
   953→        })()}
   954→
   955→        {/* Absence blocks */}
   956→        {absenceBlocks.map((absence) => (
