   973→                : "1px solid rgb(236, 72, 153)",
   974→              backdropFilter: "blur(2px)",
   975→            }}
   976→            onClick={() => {
   977→              if (absence.isPassed) {
   978→                return;
   979→              }
   980→              if (onAbsenceBlockClick) {
   981→                onAbsenceBlockClick({
   982→                  id: absence.id,
   983→                  professionalId: professional.id,
   984→                  startTime: absence.startTime,
   985→                  endTime: absence.endTime,
   986→                  reason: absence.reason,
   987→                });
   988→              }
   989→            }}
   990→          >
   991→            <div className="text-center">
   992→              <div
   993→                className={cn(
   994→                  "text-button font-bold mb-0.5",
   995→                  absence.isPassed ? "text-muted-foreground" : "text-pink-700"
   996→                )}
   997→              >
   998→                Ausência ({absence.startTime} - {absence.endTime})
   999→              </div>
  1000→              <div
  1001→                className={cn(
  1002→                  "text-button font-medium",
  1003→                  absence.isPassed ? "text-muted-foreground/80" : "text-pink-600"
  1004→                )}
  1005→              >
  1006→                <strong>Motivo: </strong>
  1007→                {absence.reason}
